+
+    if !resource_sections.is_empty() {
+        sections.push(format!(
+            "Resource diagnostics:\n{}",
+            resource_sections.join("\n")
+        ));
+    }
+
+    if sections.is_empty() {
+        (None, 0)
+    } else {
+        (
+            Some(format!("Reload diagnostics:\n\n{}", sections.join("\n\n"))),
+            count,
+        )
